 def __init__(self, size=128):
 self.size = size
 self.table = [[] for _ in range(size)] # Chaining with lists

 def _hash(self, key):
 return hash(key) % self.size

 def set(self, key, value):
 idx = self._hash(key)
 for pair in self.table[idx]:
 if pair[0] == key:
 pair[1] = value # Update existing key
 return
 self.table[idx].append([key, value])

 def get(self, key):
 idx = self._hash(key)
 for pair in self.table[idx]:
 if pair[0] == key:
 return pair[1]
 raise KeyError(key)

 def delete(self, key):
 idx = self._hash(key)
 self.table[idx] = [p for p in self.table[idx] if p[0] != key]

# Usage
ht = HashTable()
ht.set('name', 'Alice')
ht.set('age', 30)
